// ==============================
// EXCEL PROCESSING METHOD
// ==============================
private void processExcel(System.IO.Stream _stream)
{
    OfficeOpenXml.ExcelPackage package;
    OfficeOpenXml.ExcelWorksheet worksheet;
    ETGEntityMasterList entityRecord;

    int rowCount;
    int row;

    str entityCode;
    str entityName;
    str country;
    str localCurrency;
    str standardName;
    str country_1;

    try
    {
        package = new OfficeOpenXml.ExcelPackage(_stream);
        worksheet = package.get_Workbook().get_Worksheets().get_Item(1);

        rowCount = worksheet.get_Dimension().get_End().get_Row();

        ttsBegin;

        for (row = 2; row <= rowCount; row++)
        {
            entityCode     = worksheet.get_Cells().get_Item(row, 1).get_Text();
            entityName     = worksheet.get_Cells().get_Item(row, 2).get_Text();
            country        = worksheet.get_Cells().get_Item(row, 3).get_Text();
            localCurrency  = worksheet.get_Cells().get_Item(row, 4).get_Text();
            standardName   = worksheet.get_Cells().get_Item(row, 5).get_Text();
            country_1      = worksheet.get_Cells().get_Item(row, 6).get_Text();

            if (!entityCode)
            continue;

            select firstOnly forUpdate entityRecord
where entityRecord.EntityCode == entityCode;

            if (entityRecord)
            {
                // UPDATE existing record
                entityRecord.EntityName     = entityName;
                entityRecord.Country        = country;
                entityRecord.LocalCurrency  = localCurrency;
                entityRecord.StandardName   = standardName;
                entityRecord.Country_1      = country_1;

                entityRecord.update();
            }
            else
            {
                // INSERT new record
                entityRecord.clear();
                entityRecord.EntityCode     = entityCode;
                entityRecord.EntityName     = entityName;
                entityRecord.Country        = country;
                entityRecord.LocalCurrency  = localCurrency;
                entityRecord.StandardName   = standardName;
                entityRecord.Country_1      = country_1;

                entityRecord.insert();
            }
        }

        ttsCommit;
    }
    catch (Exception::CLRError)
    {
        error(CLRInterop::getLastException().ToString());
        ttsAbort;
    }
    catch (Exception::Error)
    {
        error("Excel upload failed.");
        ttsAbort;
    }
}

public void clicked()
{
    super();

    FileUploadTemporaryStorageResult uploadResult;
    System.IO.Stream stream;

    // Open file dialog
    uploadResult = File::GetFileFromUser();

    if (!uploadResult)
    {
        warning("No file selected.");
        return;
    }

    stream = uploadResult.openResult();

    // Call form method
    element.processExcel(stream);

    info("Excel upload completed successfully.");

    // Refresh grid
    ETGEntityMasterList_ds.research();
}
